func TestViewportCache(t *testing.T) {
	theme := ui.NordTheme()
	cache := NewViewportCache(24)
	buf := text.NewBufferFromBytes([]byte("test content\nline 2\nline 3"))
	v := Viewport{ScrollY: 0, Width: 80, Height: 24}

	// Initially invalid
	if cache.IsValid(buf, &v, nil, theme) {
		t.Error("Cache should be invalid initially")
	}

	// Update state
	cache.UpdateState(buf, &v, nil, theme)

	// Now valid
	if !cache.IsValid(buf, &v, nil, theme) {
		t.Error("Cache should be valid after update")
	}

	// Invalidate on scroll
	v.ScrollY = 10
	if cache.IsValid(buf, &v, nil, theme) {
		t.Error("Cache should be invalid after scroll")
	}

	// Reset and test buffer version change
	v.ScrollY = 0
	cache.UpdateState(buf, &v, nil, theme)
	if !cache.IsValid(buf, &v, nil, theme) {
		t.Error("Cache should be valid")
	}

	// Modify buffer (this increments version)
	buf.InsertAtCursor([]byte("x"))
	if cache.IsValid(buf, &v, nil, theme) {
		t.Error("Cache should be invalid after buffer modification")
	}
}

func TestViewportCacheSelection(t *testing.T) {
	theme := ui.NordTheme()
	cache := NewViewportCache(24)
	buf := text.NewBufferFromBytes([]byte("line 1\nline 2\nline 3"))
	v := Viewport{ScrollY: 0, Width: 80, Height: 24}

	// Update with no selection
	cache.UpdateState(buf, &v, nil, theme)
	if !cache.IsValid(buf, &v, nil, theme) {
		t.Error("Cache should be valid with no selection")
	}

	// Create selection
	sel := &text.Selection{
		Anchor: text.Position{Line: 0, Col: 0},
		Head:   text.Position{Line: 1, Col: 5},
	}
	if cache.IsValid(buf, &v, sel, theme) {
		t.Error("Cache should be invalid after selection created")
	}

	// Update with selection
	cache.UpdateState(buf, &v, sel, theme)
	if !cache.IsValid(buf, &v, sel, theme) {
		t.Error("Cache should be valid with selection")
	}

	// Change selection
	sel2 := &text.Selection{
		Anchor: text.Position{Line: 1, Col: 0},
		Head:   text.Position{Line: 2, Col: 5},
	}
	if cache.IsValid(buf, &v, sel2, theme) {
		t.Error("Cache should be invalid after selection changed")
	}
}

