func TestViewportCacheInvalidateLine(t *testing.T) {
	cache := NewViewportCache(24)

	// Set multiple lines
	cache.Set(0, 0, "line 0")
	cache.Set(1, 1, "line 1")
	cache.Set(2, 2, "line 2")

	// Verify all cached
	for i := 0; i < 3; i++ {
		if _, ok := cache.Get(i); !ok {
			t.Errorf("Line %d should be cached", i)
		}
	}

	// Invalidate line 1
	cache.InvalidateLine(1)

	// Verify line 1 invalidated, others still valid
	if _, ok := cache.Get(0); !ok {
		t.Error("Line 0 should still be cached")
	}
	if _, ok := cache.Get(1); ok {
		t.Error("Line 1 should be invalidated")
	}
	if _, ok := cache.Get(2); !ok {
		t.Error("Line 2 should still be cached")
	}
}

