func TestViewportCacheResize(t *testing.T) {
	cache := NewViewportCache(24)

	// Set values at various rows
	cache.Set(0, 0, "line 0")
	cache.Set(10, 10, "line 10")
	cache.Set(23, 23, "line 23")

	// Shrink cache
	cache.Resize(12)

	// Verify accessible rows are preserved
	if _, ok := cache.Get(0); !ok {
		t.Error("Row 0 should still be cached after shrink")
	}
	if _, ok := cache.Get(10); !ok {
		t.Error("Row 10 should still be cached after shrink")
	}

	// Verify out-of-bounds access returns false
	if _, ok := cache.Get(23); ok {
		t.Error("Row 23 should be out of bounds after shrink")
	}

	// Grow cache back
	cache.Resize(24)

	// Verify original values still there (within new bounds)
	if _, ok := cache.Get(0); !ok {
		t.Error("Row 0 should be cached after grow")
	}
}

func TestComputeSelectionHash(t *testing.T) {
	// Empty selection
	if hash := computeSelectionHash(nil); hash != 0 {
		t.Errorf("Empty selection hash should be 0, got %d", hash)
	}

	emptySel := &text.Selection{}
	if hash := computeSelectionHash(emptySel); hash != 0 {
		t.Errorf("Empty selection hash should be 0, got %d", hash)
	}

	// Non-empty selection
	sel := &text.Selection{
		Anchor: text.Position{Line: 5, Col: 10},
		Head:   text.Position{Line: 10, Col: 20},
	}
	hash1 := computeSelectionHash(sel)
	if hash1 == 0 {
		t.Error("Non-empty selection should have non-zero hash")
	}

	// Same selection should produce same hash
	sel2 := &text.Selection{
		Anchor: text.Position{Line: 5, Col: 10},
		Head:   text.Position{Line: 10, Col: 20},
	}
	hash2 := computeSelectionHash(sel2)
	if hash1 != hash2 {
		t.Error("Same selection should produce same hash")
	}

	// Different selection should produce different hash (probably)
	sel3 := &text.Selection{
		Anchor: text.Position{Line: 1, Col: 0},
		Head:   text.Position{Line: 20, Col: 5},
	}
	hash3 := computeSelectionHash(sel3)
	if hash1 == hash3 {
		t.Error("Different selection should produce different hash")
	}
}

